cat > /tmp/codeceptjs-onresponse-edge.js <<'EOF'
const path = require('path')
const repo = '/workspace/CodeceptJS'
process.chdir(repo)
global.codeceptjs = require(path.join(repo, 'lib'))
const Container = require(path.join(repo, 'lib/container'))

async function withContainer(config, fn) {
  Container.create(config)
  try {
    await fn(Container.helpers('REST'), Container.helpers('JSONResponse'))
  } finally {
    Container.clear()
  }
}

async function main() {
  await withContainer({ helpers: { REST: { endpoint: 'http://127.0.0.1:8010' }, JSONResponse: {} } }, async (rest, jsonResponse) => {
    jsonResponse._beforeSuite()
    await rest.sendGetRequest('/user')
    if (!jsonResponse.response || jsonResponse.response.status !== 200) throw new Error('JSONResponse did not capture response without user onResponse')
  })

  let awaited = false
  await withContainer({
    helpers: {
      REST: {
        endpoint: 'http://127.0.0.1:8010',
        onResponse: async response => {
          await new Promise(resolve => setTimeout(resolve, 20))
          awaited = true
          response.headers['x-async-hook'] = 'ok'
        },
      },
      JSONResponse: {},
    },
  }, async (rest, jsonResponse) => {
    jsonResponse._beforeSuite()
    await rest.sendGetRequest('/user')
    if (!awaited) throw new Error('async onResponse was not awaited')
    if (jsonResponse.response.headers['x-async-hook'] !== 'ok') throw new Error('async onResponse mutation missing from JSONResponse response')
  })

  console.log('edge checks passed')
}

main().catch(err => {
  console.error(err.stack || err.message)
  Container.clear()
  process.exit(1)
})
EOF
